html:
/* ============================================
   LIGHTRUX BLOGGER THEME
   Dark Techy • Professional • Fast
   ============================================ */

/* --- CSS Variables (Easy Customization) --- */
:root {
  --bg-primary: #000000;
  --bg-secondary: #080d1a;
  --bg-card: #0c1220;
  --bg-card-hover: #111827;
  --blue-primary: #4DB8FF;
  --blue-deep: #1A3A6B;
  --blue-glow: rgba(77, 184, 255, 0.15);
  --blue-glow-strong: rgba(77, 184, 255, 0.3);
  --text-primary: #F0F6FF;
  --text-secondary: #8BA5C4;
  --text-muted: #4A6080;
  --border: rgba(77, 184, 255, 0.12);
  --border-hover: rgba(77, 184, 255, 0.35);
  --font-display: 'Orbitron', 'Exo 2', sans-serif;
  --font-body: 'Exo 2', 'Rajdhani', sans-serif;
  --radius: 8px;
  --radius-lg: 14px;
  --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

/* --- Reset & Base --- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { scroll-behavior: smooth; }

body {
  background: var(--bg-primary);
  color: var(--text-primary);
  font-family: var(--font-body);
  font-size: 16px;
  line-height: 1.7;
  overflow-x: hidden;
  -webkit-font-smoothing: antialiased;
}

/* Star field background */
body::before {
  content: '';
  position: fixed;
  top: 0; left: 0;
  width: 100%; height: 100%;
  background-image:
    radial-gradient(1px 1px at 10% 15%, rgba(77,184,255,0.6) 0%, transparent 100%),
    radial-gradient(1px 1px at 25% 40%, rgba(255,255,255,0.4) 0%, transparent 100%),
    radial-gradient(1px 1px at 50% 10%, rgba(77,184,255,0.5) 0%, transparent 100%),
    radial-gradient(1px 1px at 70% 60%, rgba(255,255,255,0.3) 0%, transparent 100%),
    radial-gradient(1px 1px at 85% 25%, rgba(77,184,255,0.4) 0%, transparent 100%),
    radial-gradient(1px 1px at 90% 80%, rgba(255,255,255,0.3) 0%, transparent 100%),
    radial-gradient(1px 1px at 35% 75%, rgba(77,184,255,0.3) 0%, transparent 100%),
    radial-gradient(1px 1px at 60% 90%, rgba(255,255,255,0.2) 0%, transparent 100%),
    radial-gradient(2px 2px at 15% 55%, rgba(77,184,255,0.2) 0%, transparent 100%),
    radial-gradient(1px 1px at 45% 30%, rgba(255,255,255,0.3) 0%, transparent 100%);
  pointer-events: none;
  z-index: 0;
}

a { color: var(--blue-primary); text-decoration: none; transition: var(--transition); }
a:hover { color: #fff; }
img { max-width: 100%; height: auto; display: block; }
ul { list-style: none; }

/* --- Google Fonts --- */
@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;600;700;900&family=Exo+2:wght@300;400;500;600;700&display=swap');

/* ============================================
   HEADER & NAVIGATION
   ============================================ */
#lx-header {
  position: fixed;
  top: 0; left: 0; right: 0;
  z-index: 1000;
  background: rgba(0, 0, 0, 0.85);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--border);
  transition: var(--transition);
}

#lx-header.scrolled {
  background: rgba(0, 5, 15, 0.95);
  border-bottom-color: var(--border-hover);
  box-shadow: 0 4px 30px rgba(77, 184, 255, 0.08);
}

.lx-nav-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 68px;
}

/* Logo */
.lx-logo {
  display: flex;
  align-items: center;
  gap: 10px;
  text-decoration: none;
  flex-shrink: 0;
}

.lx-logo img {
  height: 42px;
  width: 42px;
  border-radius: 50%;
  object-fit: cover;
  border: 1.5px solid var(--border-hover);
  box-shadow: 0 0 12px rgba(77,184,255,0.25);
}

.lx-logo-text {
  font-family: var(--font-display);
  font-size: 1.25rem;
  font-weight: 700;
  color: #fff;
  letter-spacing: 0.05em;
}

.lx-logo-text span {
  color: var(--blue-primary);
}

/* Desktop Nav */
.lx-nav-menu {
  display: flex;
  align-items: center;
  gap: 4px;
}

.lx-nav-menu > li {
  position: relative;
}

.lx-nav-menu > li > a {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 8px 14px;
  font-family: var(--font-body);
  font-size: 0.875rem;
  font-weight: 500;
  color: var(--text-secondary);
  border-radius: var(--radius);
  transition: var(--transition);
  letter-spacing: 0.03em;
  text-transform: uppercase;
}

.lx-nav-menu > li > a:hover,
.lx-nav-menu > li > a.active {
  color: var(--blue-primary);
  background: var(--blue-glow);
}

/* Dropdown arrow */
.lx-nav-menu > li > a .lx-arrow {
  font-size: 0.6rem;
  opacity: 0.6;
  transition: var(--transition);
}

.lx-nav-menu > li:hover > a .lx-arrow {
  transform: rotate(180deg);
  opacity: 1;
}

/* Dropdown */
.lx-dropdown {
  position: absolute;
  top: calc(100% + 8px);
  left: 0;
  min-width: 200px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 8px;
  opacity: 0;
  visibility: hidden;
  transform: translateY(-8px);
  transition: var(--transition);
  box-shadow: 0 20px 60px rgba(0,0,0,0.6), 0 0 0 1px rgba(77,184,255,0.05);
  z-index: 100;
}

.lx-nav-menu > li:hover .lx-dropdown {
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
}

.lx-dropdown a {
  display: block;
  padding: 9px 14px;
  font-size: 0.85rem;
  color: var(--text-secondary);
  border-radius: 6px;
  transition: var(--transition);
}

.lx-dropdown a:hover {
  color: var(--blue-primary);
  background: var(--blue-glow);
}

/* Nav Right */
.lx-nav-right {
  display: flex;
  align-items: center;
  gap: 12px;
}

/* Search button */
.lx-search-btn {
  background: none;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  width: 36px;
  height: 36px;
  border-radius: var(--radius);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: var(--transition);
  font-size: 0.9rem;
}

.lx-search-btn:hover {
  border-color: var(--blue-primary);
  color: var(--blue-primary);
  background: var(--blue-glow);
}

/* Hamburger */
.lx-hamburger {
  display: none;
  flex-direction: column;
  gap: 5px;
  background: none;
  border: none;
  cursor: pointer;
  padding: 6px;
}

.lx-hamburger span {
  display: block;
  width: 24px;
  height: 2px;
  background: var(--text-secondary);
  border-radius: 2px;
  transition: var(--transition);
}

.lx-hamburger.open span:nth-child(1) { transform: translateY(7px) rotate(45deg); background: var(--blue-primary); }
.lx-hamburger.open span:nth-child(2) { opacity: 0; }
.lx-hamburger.open span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); background: var(--blue-primary); }

/* Mobile menu */
.lx-mobile-menu {
  display: none;
  position: fixed;
  top: 68px; left: 0; right: 0;
  background: rgba(0, 5, 15, 0.97);
  backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--border);
  padding: 16px 24px 24px;
  z-index: 999;
  max-height: calc(100vh - 68px);
  overflow-y: auto;
}

.lx-mobile-menu.open { display: block; }

.lx-mobile-menu a {
  display: block;
  padding: 12px 16px;
  color: var(--text-secondary);
  font-size: 0.95rem;
  border-radius: var(--radius);
  margin-bottom: 2px;
  transition: var(--transition);
}

.lx-mobile-menu a:hover {
  color: var(--blue-primary);
  background: var(--blue-glow);
}

.lx-mobile-sub {
  padding-left: 16px;
  border-left: 1px solid var(--border);
  margin-left: 16px;
  margin-top: 2px;
}

/* Search Overlay */
.lx-search-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(0,0,0,0.92);
  z-index: 2000;
  display: none;
  align-items: center;
  justify-content: center;
  padding: 24px;
}

.lx-search-overlay.open { display: flex; }

.lx-search-box {
  width: 100%;
  max-width: 600px;
}

.lx-search-box input {
  width: 100%;
  background: var(--bg-card);
  border: 1px solid var(--border-hover);
  border-radius: var(--radius-lg);
  padding: 16px 20px;
  font-size: 1.1rem;
  color: var(--text-primary);
  font-family: var(--font-body);
  outline: none;
}

.lx-search-box input:focus {
  border-color: var(--blue-primary);
  box-shadow: 0 0 20px var(--blue-glow-strong);
}

.lx-search-close {
  display: block;
  margin-top: 12px;
  text-align: center;
  color: var(--text-muted);
  font-size: 0.85rem;
  cursor: pointer;
}

/* ============================================
   HERO SECTION
   ============================================ */
#lx-hero {
  position: relative;
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 120px 24px 80px;
  overflow: hidden;
}

/* Hero background glow */
#lx-hero::before {
  content: '';
  position: absolute;
  top: 20%;
  left: 50%;
  transform: translateX(-50%);
  width: 600px;
  height: 600px;
  background: radial-gradient(circle, rgba(77,184,255,0.08) 0%, rgba(26,58,107,0.05) 40%, transparent 70%);
  pointer-events: none;
  z-index: 0;
}

/* Orbit rings */
#lx-hero::after {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 700px;
  height: 700px;
  border: 1px solid rgba(77,184,255,0.05);
  border-radius: 50%;
  pointer-events: none;
  animation: lx-orbit-pulse 6s ease-in-out infinite;
}

@keyframes lx-orbit-pulse {
  0%, 100% { transform: translate(-50%, -50%) scale(1); opacity: 0.5; }
  50% { transform: translate(-50%, -50%) scale(1.05); opacity: 1; }
}

.lx-hero-inner {
  position: relative;
  z-index: 1;
  max-width: 760px;
}

.lx-hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: var(--blue-glow);
  border: 1px solid var(--border-hover);
  border-radius: 100px;
  padding: 6px 16px;
  font-size: 0.78rem;
  font-weight: 600;
  color: var(--blue-primary);
  letter-spacing: 0.1em;
  text-transform: uppercase;
  margin-bottom: 28px;
  animation: lx-fade-up 0.8s ease both;
}

.lx-hero-badge::before {
  content: '';
  width: 6px;
  height: 6px;
  background: var(--blue-primary);
  border-radius: 50%;
  box-shadow: 0 0 8px var(--blue-primary);
  animation: lx-blink 2s ease-in-out infinite;
}

@keyframes lx-blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.3; }
}

.lx-hero-logo {
  width: 110px;
  height: 110px;
  border-radius: 50%;
  object-fit: cover;
  margin: 0 auto 28px;
  border: 2px solid rgba(77,184,255,0.3);
  box-shadow:
    0 0 0 8px rgba(77,184,255,0.05),
    0 0 40px rgba(77,184,255,0.2),
    0 0 80px rgba(77,184,255,0.1);
  animation: lx-fade-up 0.9s ease 0.1s both;
}

.lx-hero-title {
  font-family: var(--font-display);
  font-size: clamp(2.5rem, 6vw, 4rem);
  font-weight: 900;
  color: #fff;
  letter-spacing: 0.06em;
  line-height: 1.1;
  margin-bottom: 20px;
  animation: lx-fade-up 1s ease 0.2s both;
}

.lx-hero-title .lx-glow {
  color: var(--blue-primary);
  text-shadow: 0 0 30px rgba(77,184,255,0.5), 0 0 60px rgba(77,184,255,0.2);
}

.lx-hero-sub {
  font-size: 1.1rem;
  color: var(--text-secondary);
  max-width: 520px;
  margin: 0 auto 36px;
  font-weight: 400;
  line-height: 1.7;
  animation: lx-fade-up 1s ease 0.3s both;
}

.lx-hero-cta {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  background: var(--blue-primary);
  color: #000;
  font-family: var(--font-display);
  font-size: 0.82rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 14px 28px;
  border-radius: var(--radius);
  transition: var(--transition);
  animation: lx-fade-up 1s ease 0.4s both;
  box-shadow: 0 4px 24px rgba(77,184,255,0.3);
}

.lx-hero-cta:hover {
  background: #fff;
  color: #000;
  transform: translateY(-2px);
  box-shadow: 0 8px 40px rgba(77,184,255,0.4);
}

.lx-hero-cta svg {
  width: 16px;
  height: 16px;
  transition: var(--transition);
}

.lx-hero-cta:hover svg {
  transform: translateY(4px);
}

/* Scroll indicator */
.lx-scroll-hint {
  position: absolute;
  bottom: 32px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  color: var(--text-muted);
  font-size: 0.72rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  animation: lx-fade-up 1s ease 0.8s both;
}

.lx-scroll-line {
  width: 1px;
  height: 32px;
  background: linear-gradient(to bottom, var(--blue-primary), transparent);
  animation: lx-scroll-anim 2s ease-in-out infinite;
}

@keyframes lx-scroll-anim {
  0% { transform: scaleY(0); transform-origin: top; }
  50% { transform: scaleY(1); transform-origin: top; }
  51% { transform: scaleY(1); transform-origin: bottom; }
  100% { transform: scaleY(0); transform-origin: bottom; }
}

@keyframes lx-fade-up {
  from { opacity: 0; transform: translateY(24px); }
  to { opacity: 1; transform: translateY(0); }
}

/* ============================================
   MAIN CONTENT WRAPPER
   ============================================ */
#lx-main {
  max-width: 1200px;
  margin: 0 auto;
  padding: 60px 24px 80px;
  display: grid;
  grid-template-columns: 1fr 320px;
  gap: 40px;
  position: relative;
  z-index: 1;
}

/* Section heading */
.lx-section-heading {
  display: flex;
  align-items: center;
  gap: 14px;
  margin-bottom: 32px;
}

.lx-section-heading h2 {
  font-family: var(--font-display);
  font-size: 1rem;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.lx-section-line {
  flex: 1;
  height: 1px;
  background: linear-gradient(to right, var(--border-hover), transparent);
}

.lx-section-dot {
  width: 6px;
  height: 6px;
  background: var(--blue-primary);
  border-radius: 50%;
  box-shadow: 0 0 8px var(--blue-primary);
  flex-shrink: 0;
}

/* ============================================
   BLOG POST CARDS
   ============================================ */
.lx-posts-grid {
  display: grid;
  gap: 24px;
}

.lx-post-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  overflow: hidden;
  transition: var(--transition);
  position: relative;
}

.lx-post-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 2px;
  background: linear-gradient(to right, transparent, var(--blue-primary), transparent);
  opacity: 0;
  transition: var(--transition);
}

.lx-post-card:hover {
  border-color: var(--border-hover);
  transform: translateY(-3px);
  box-shadow: 0 12px 40px rgba(0,0,0,0.4), 0 0 0 1px rgba(77,184,255,0.08);
  background: var(--bg-card-hover);
}

.lx-post-card:hover::before {
  opacity: 1;
}

.lx-post-thumb {
  width: 100%;
  height: 200px;
  object-fit: cover;
  display: block;
  transition: var(--transition);
}

.lx-post-card:hover .lx-post-thumb {
  transform: scale(1.02);
}

.lx-post-thumb-wrap {
  overflow: hidden;
  position: relative;
}

.lx-post-thumb-placeholder {
  width: 100%;
  height: 200px;
  background: linear-gradient(135deg, var(--bg-secondary) 0%, var(--blue-deep) 100%);
  display: flex;
  align-items: center;
  justify-content: center;
}

.lx-post-thumb-placeholder svg {
  width: 48px;
  height: 48px;
  opacity: 0.2;
  color: var(--blue-primary);
}

.lx-post-label {
  display: inline-block;
  font-size: 0.7rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--blue-primary);
  background: var(--blue-glow);
  border: 1px solid rgba(77,184,255,0.2);
  border-radius: 4px;
  padding: 3px 10px;
  margin-bottom: 10px;
}

.lx-post-body {
  padding: 22px 24px 24px;
}

.lx-post-title {
  font-family: var(--font-display);
  font-size: 1rem;
  font-weight: 600;
  color: var(--text-primary);
  line-height: 1.45;
  margin-bottom: 10px;
  letter-spacing: 0.02em;
  transition: var(--transition);
}

.lx-post-card:hover .lx-post-title {
  color: var(--blue-primary);
}

.lx-post-snippet {
  font-size: 0.875rem;
  color: var(--text-secondary);
  line-height: 1.65;
  margin-bottom: 16px;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.lx-post-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: 0.78rem;
  color: var(--text-muted);
}

.lx-post-meta-left {
  display: flex;
  align-items: center;
  gap: 12px;
}

.lx-post-date {
  display: flex;
  align-items: center;
  gap: 5px;
}

.lx-read-more {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 0.78rem;
  font-weight: 600;
  color: var(--blue-primary);
  letter-spacing: 0.05em;
  text-transform: uppercase;
  transition: var(--transition);
}

.lx-read-more:hover {
  gap: 10px;
  color: #fff;
}

/* Pagination */
.lx-pagination {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  margin-top: 40px;
}

.lx-pagination a,
.lx-pagination span {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  border-radius: var(--radius);
  font-size: 0.85rem;
  font-weight: 500;
  border: 1px solid var(--border);
  color: var(--text-secondary);
  transition: var(--transition);
}

.lx-pagination a:hover {
  border-color: var(--blue-primary);
  color: var(--blue-primary);
  background: var(--blue-glow);
}

/* ============================================
   SIDEBAR
   ============================================ */
#lx-sidebar {
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.lx-widget {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 24px;
  transition: var(--transition);
}

.lx-widget:hover {
  border-color: rgba(77,184,255,0.2);
}

.lx-widget-title {
  font-family: var(--font-display);
  font-size: 0.78rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--blue-primary);
  margin-bottom: 18px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  gap: 8px;
}

.lx-widget-title::before {
  content: '';
  width: 3px;
  height: 14px;
  background: var(--blue-primary);
  border-radius: 2px;
  box-shadow: 0 0 8px rgba(77,184,255,0.5);
}

/* About widget */
.lx-about-widget {
  text-align: center;
}

.lx-about-logo {
  width: 72px;
  height: 72px;
  border-radius: 50%;
  object-fit: cover;
  margin: 0 auto 14px;
  border: 2px solid rgba(77,184,255,0.3);
  box-shadow: 0 0 20px rgba(77,184,255,0.15);
}

.lx-about-name {
  font-family: var(--font-display);
  font-size: 1rem;
  font-weight: 700;
  color: #fff;
  margin-bottom: 8px;
}

.lx-about-desc {
  font-size: 0.83rem;
  color: var(--text-secondary);
  line-height: 1.6;
}

/* Social icons */
.lx-social-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 8px;
}

.lx-social-link {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 5px;
  padding: 10px 6px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text-muted);
  font-size: 0.65rem;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  transition: var(--transition);
}

.lx-social-link svg {
  width: 18px;
  height: 18px;
}

.lx-social-link:hover {
  border-color: var(--border-hover);
  color: var(--blue-primary);
  background: var(--blue-glow);
  transform: translateY(-2px);
}

/* Categories widget */
.lx-category-list {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.lx-category-list a {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 9px 12px;
  border-radius: var(--radius);
  color: var(--text-secondary);
  font-size: 0.85rem;
  transition: var(--transition);
  border: 1px solid transparent;
}

.lx-category-list a:hover {
  color: var(--blue-primary);
  background: var(--blue-glow);
  border-color: var(--border);
}

.lx-category-count {
  font-size: 0.72rem;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: 4px;
  padding: 2px 7px;
  color: var(--text-muted);
}

/* Popular posts widget */
.lx-popular-list {
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.lx-popular-item {
  display: flex;
  gap: 12px;
  align-items: flex-start;
}

.lx-popular-num {
  font-family: var(--font-display);
  font-size: 1.2rem;
  font-weight: 900;
  color: var(--border-hover);
  line-height: 1;
  flex-shrink: 0;
  min-width: 24px;
}

.lx-popular-title {
  font-size: 0.83rem;
  color: var(--text-secondary);
  line-height: 1.5;
  transition: var(--transition);
}

.lx-popular-item:hover .lx-popular-title {
  color: var(--blue-primary);
}

/* Search widget */
.lx-search-widget {
  position: relative;
}

.lx-search-widget input {
  width: 100%;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 11px 44px 11px 14px;
  font-size: 0.875rem;
  color: var(--text-primary);
  font-family: var(--font-body);
  outline: none;
  transition: var(--transition);
}

.lx-search-widget input:focus {
  border-color: var(--blue-primary);
  box-shadow: 0 0 0 3px var(--blue-glow);
}

.lx-search-widget input::placeholder {
  color: var(--text-muted);
}

.lx-search-widget button {
  position: absolute;
  right: 10px;
  top: 50%;
  transform: translateY(-50%);
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  transition: var(--transition);
  display: flex;
}

.lx-search-widget button:hover {
  color: var(--blue-primary);
}

/* ============================================
   FOOTER
   ============================================ */
#lx-footer {
  background: var(--bg-secondary);
  border-top: 1px solid var(--border);
  position: relative;
  z-index: 1;
}

.lx-footer-top {
  max-width: 1200px;
  margin: 0 auto;
  padding: 56px 24px 40px;
  display: grid;
  grid-template-columns: 1.5fr 1fr 1fr 1fr;
  gap: 40px;
}

.lx-footer-brand .lx-logo {
  margin-bottom: 14px;
}

.lx-footer-brand p {
  font-size: 0.85rem;
  color: var(--text-secondary);
  line-height: 1.65;
  max-width: 240px;
  margin-bottom: 20px;
}

.lx-footer-social {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.lx-footer-social a {
  width: 34px;
  height: 34px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-muted);
  transition: var(--transition);
}

.lx-footer-social a:hover {
  border-color: var(--blue-primary);
  color: var(--blue-primary);
  background: var(--blue-glow);
}

.lx-footer-social a svg {
  width: 15px;
  height: 15px;
}

.lx-footer-col h4 {
  font-family: var(--font-display);
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--text-primary);
  margin-bottom: 16px;
}

.lx-footer-col ul {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.lx-footer-col ul a {
  font-size: 0.85rem;
  color: var(--text-muted);
  transition: var(--transition);
}

.lx-footer-col ul a:hover {
  color: var(--blue-primary);
  padding-left: 4px;
}

.lx-footer-bottom {
  border-top: 1px solid var(--border);
  padding: 18px 24px;
}

.lx-footer-bottom-inner {
  max-width: 1200px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 8px;
}

.lx-footer-bottom p {
  font-size: 0.8rem;
  color: var(--text-muted);
}

.lx-footer-bottom p span {
  color: var(--blue-primary);
}

/* ============================================
   SINGLE POST PAGE
   ============================================ */
.lx-post-header {
  max-width: 800px;
  margin: 0 auto;
  padding: 100px 24px 40px;
  text-align: center;
}

.lx-post-header .lx-post-label {
  margin-bottom: 16px;
}

.lx-post-header h1 {
  font-family: var(--font-display);
  font-size: clamp(1.6rem, 4vw, 2.4rem);
  font-weight: 700;
  color: #fff;
  line-height: 1.3;
  margin-bottom: 16px;
  letter-spacing: 0.02em;
}

.lx-post-info {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 16px;
  flex-wrap: wrap;
  font-size: 0.82rem;
  color: var(--text-muted);
  margin-bottom: 32px;
}

.lx-post-info span {
  display: flex;
  align-items: center;
  gap: 5px;
}

.lx-featured-image {
  max-width: 900px;
  margin: 0 auto 48px;
  padding: 0 24px;
}

.lx-featured-image img {
  width: 100%;
  border-radius: var(--radius-lg);
  border: 1px solid var(--border);
  box-shadow: 0 20px 60px rgba(0,0,0,0.5);
}

/* Post content */
.lx-post-content {
  max-width: 780px;
  margin: 0 auto;
  padding: 0 24px 60px;
  font-size: 1rem;
  color: var(--text-secondary);
  line-height: 1.85;
}

.lx-post-content h1,
.lx-post-content h2,
.lx-post-content h3,
.lx-post-content h4 {
  font-family: var(--font-display);
  color: var(--text-primary);
  margin: 36px 0 14px;
  letter-spacing: 0.02em;
}

.lx-post-content h2 { font-size: 1.45rem; font-weight: 700; }
.lx-post-content h3 { font-size: 1.2rem; font-weight: 600; }
.lx-post-content h4 { font-size: 1rem; font-weight: 600; }

.lx-post-content p { margin-bottom: 20px; }

.lx-post-content a {
  color: var(--blue-primary);
  border-bottom: 1px solid rgba(77,184,255,0.3);
}

.lx-post-content a:hover {
  border-bottom-color: var(--blue-primary);
}

.lx-post-content ul,
.lx-post-content ol {
  padding-left: 24px;
  margin-bottom: 20px;
}

.lx-post-content ul { list-style: none; }

.lx-post-content ul li {
  position: relative;
  padding-left: 18px;
  margin-bottom: 8px;
}

.lx-post-content ul li::before {
  content: '';
  position: absolute;
  left: 0;
  top: 10px;
  width: 6px;
  height: 6px;
  background: var(--blue-primary);
  border-radius: 50%;
  box-shadow: 0 0 6px rgba(77,184,255,0.5);
}

.lx-post-content ol li { margin-bottom: 8px; }

.lx-post-content blockquote {
  border-left: 3px solid var(--blue-primary);
  background: var(--bg-card);
  padding: 16px 20px;
  border-radius: 0 var(--radius) var(--radius) 0;
  margin: 24px 0;
  color: var(--text-secondary);
  font-style: italic;
}

.lx-post-content pre {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
  overflow-x: auto;
  margin: 24px 0;
  font-size: 0.875rem;
}

.lx-post-content code {
  font-family: 'Courier New', monospace;
  font-size: 0.875em;
  background: var(--bg-card);
  border: 1px solid var(--border);
  padding: 2px 6px;
  border-radius: 4px;
  color: var(--blue-primary);
}

.lx-post-content img {
  border-radius: var(--radius);
  border: 1px solid var(--border);
  margin: 24px 0;
}

.lx-post-content hr {
  border: none;
  border-top: 1px solid var(--border);
  margin: 36px 0;
}

/* Post tags */
.lx-post-tags {
  max-width: 780px;
  margin: 0 auto 40px;
  padding: 0 24px;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.lx-post-tags a {
  font-size: 0.78rem;
  padding: 5px 12px;
  border: 1px solid var(--border);
  border-radius: 100px;
  color: var(--text-muted);
  transition: var(--transition);
}

.lx-post-tags a:hover {
  border-color: var(--blue-primary);
  color: var(--blue-primary);
  background: var(--blue-glow);
}

/* Share buttons */
.lx-share {
  max-width: 780px;
  margin: 0 auto 48px;
  padding: 24px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 12px;
  margin-left: 24px;
  margin-right: 24px;
}

.lx-share-label {
  font-family: var(--font-display);
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-right: 4px;
}

.lx-share a {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 8px 14px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  font-size: 0.8rem;
  font-weight: 500;
  color: var(--text-secondary);
  transition: var(--transition);
}

.lx-share a:hover {
  border-color: var(--border-hover);
  color: var(--blue-primary);
  background: var(--blue-glow);
}

/* Comments */
.lx-comments {
  max-width: 780px;
  margin: 0 auto;
  padding: 0 24px 60px;
}

.lx-comments h3 {
  font-family: var(--font-display);
  font-size: 0.9rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--text-primary);
  margin-bottom: 24px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--border);
}

/* ============================================
   UTILITY
   ============================================ */
.lx-divider {
  width: 100%;
  height: 1px;
  background: linear-gradient(to right, transparent, var(--border), transparent);
  margin: 40px 0;
}

.lx-back-top {
  position: fixed;
  bottom: 28px;
  right: 28px;
  width: 42px;
  height: 42px;
  background: var(--bg-card);
  border: 1px solid var(--border-hover);
  border-radius: var(--radius);
  color: var(--blue-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: var(--transition);
  z-index: 900;
  opacity: 0;
  pointer-events: none;
}

.lx-back-top.visible {
  opacity: 1;
  pointer-events: all;
}

.lx-back-top:hover {
  background: var(--blue-primary);
  color: #000;
  transform: translateY(-3px);
  box-shadow: 0 8px 24px rgba(77,184,255,0.3);
}

/* ============================================
   STATIC PAGES
   ============================================ */
.lx-page-header {
  max-width: 800px;
  margin: 0 auto;
  padding: 100px 24px 40px;
  text-align: center;
}

.lx-page-header h1 {
  font-family: var(--font-display);
  font-size: clamp(1.8rem, 4vw, 2.6rem);
  font-weight: 700;
  color: #fff;
  letter-spacing: 0.04em;
  margin-bottom: 12px;
}

.lx-page-header p {
  color: var(--text-secondary);
  font-size: 1rem;
}

.lx-page-content {
  max-width: 780px;
  margin: 0 auto;
  padding: 0 24px 80px;
}

/* ============================================
   RESPONSIVE
   ============================================ */
@media (max-width: 1024px) {
  #lx-main {
    grid-template-columns: 1fr;
  }

  #lx-sidebar {
    display: grid;
    grid-template-columns: 1fr 1fr;
  }

  .lx-footer-top {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 768px) {
  .lx-nav-menu { display: none; }
  .lx-hamburger { display: flex; }

  #lx-sidebar {
    grid-template-columns: 1fr;
  }

  .lx-footer-top {
    grid-template-columns: 1fr;
    gap: 28px;
  }

  .lx-footer-bottom-inner {
    flex-direction: column;
    text-align: center;
  }

  .lx-share {
    margin-left: 0;
    margin-right: 0;
  }
}

@media (max-width: 480px) {
  .lx-hero-title { font-size: 2rem; }
  .lx-social-grid { grid-template-columns: repeat(3, 1fr); }
  .lx-back-top { bottom: 16px; right: 16px; }
}

/* ============================================
   BLOGGER WIDGET OVERRIDES
   ============================================ */
.widget { margin-bottom: 0 !important; }
.widget-content { margin: 0 !important; }
#blog-pager { text-align: center; margin-top: 32px; }
#blog-pager a {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 9px 18px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text-secondary);
  font-size: 0.85rem;
  margin: 0 4px;
  transition: var(--transition);
}
#blog-pager a:hover {
  border-color: var(--blue-primary);
  color: var(--blue-primary);
  background: var(--blue-glow);
}
.post-footer { display: none; }

