(function() {
  'use strict';

  // Sticky header
  var header = document.getElementById('lx-header');
  window.addEventListener('scroll', function() {
    if (window.scrollY > 40) {
      header.classList.add('scrolled');
    } else {
      header.classList.remove('scrolled');
    }
  });

  // Hamburger menu
  var hamburger = document.getElementById('lx-hamburger');
  var mobileMenu = document.getElementById('lx-mobile-menu');
  if (hamburger && mobileMenu) {
    hamburger.addEventListener('click', function() {
      hamburger.classList.toggle('open');
      mobileMenu.classList.toggle('open');
    });
  }

  // Search overlay
  var searchOpen = document.getElementById('lx-search-open');
  var searchOverlay = document.getElementById('lx-search-overlay');
  var searchClose = document.getElementById('lx-search-close');
  var searchInput = document.getElementById('lx-search-input');

  if (searchOpen && searchOverlay) {
    searchOpen.addEventListener('click', function() {
      searchOverlay.classList.add('open');
      if (searchInput) setTimeout(function() { searchInput.focus(); }, 100);
    });
  }

  if (searchClose && searchOverlay) {
    searchClose.addEventListener('click', function() {
      searchOverlay.classList.remove('open');
    });
  }

  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape' && searchOverlay) {
      searchOverlay.classList.remove('open');
    }
  });

  // Search functionality
  function doSearch(query) {
    if (query && query.trim()) {
      window.location.href = '/search?q=' + encodeURIComponent(query.trim());
    }
  }

  if (searchInput) {
    searchInput.addEventListener('keydown', function(e) {
      if (e.key === 'Enter') doSearch(this.value);
    });
  }

  var sidebarSearch = document.getElementById('lx-sidebar-search');
  if (sidebarSearch) {
    sidebarSearch.addEventListener('keydown', function(e) {
      if (e.key === 'Enter') doSearch(this.value);
    });
    var sidebarBtn = sidebarSearch.nextElementSibling;
    if (sidebarBtn) {
      sidebarBtn.addEventListener('click', function() {
        doSearch(sidebarSearch.value);
      });
    }
  }

  // Back to top
  var backTop = document.getElementById('lx-back-top');
  if (backTop) {
    window.addEventListener('scroll', function() {
      if (window.scrollY > 400) {
        backTop.classList.add('visible');
      } else {
        backTop.classList.remove('visible');
      }
    });
    backTop.addEventListener('click', function() {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    });
  }

  // Highlight active nav link
  var currentUrl = window.location.href;
  var navLinks = document.querySelectorAll('.lx-nav-menu a');
  navLinks.forEach(function(link) {
    if (link.href === currentUrl || (link.href !== window.location.origin + '/' && currentUrl.indexOf(link.href) === 0)) {
      link.classList.add('active');
    }
  });

  // Hero CTA smooth scroll
  var heroCta = document.querySelector('.lx-hero-cta');
  if (heroCta) {
    heroCta.addEventListener('click', function(e) {
      e.preventDefault();
      var target = document.getElementById('lx-main');
      if (target) {
        target.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    });
  }

  // Fade-in posts on scroll
  var cards = document.querySelectorAll('.lx-post-card');
  if ('IntersectionObserver' in window) {
    var observer = new IntersectionObserver(function(entries) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          entry.target.style.opacity = '1';
          entry.target.style.transform = 'translateY(0)';
          observer.unobserve(entry.target);
        }
      });
    }, { threshold: 0.1 });

    cards.forEach(function(card, i) {
      card.style.opacity = '0';
      card.style.transform = 'translateY(20px)';
      card.style.transition = 'opacity 0.5s ease ' + (i * 0.08) + 's, transform 0.5s ease ' + (i * 0.08) + 's, border-color 0.3s, box-shadow 0.3s, background 0.3s';
      observer.observe(card);
    });
  }

})();
